import{_ as o,o as c,c as d,a2 as t}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"架构","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/architecture.md","filePath":"zh/guide/architecture.md"}'),r={name:"zh/guide/architecture.md"};function a(l,e,i,s,n,_){return c(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h1><h2 id="解析机制" tabindex="-1">解析机制 <a class="header-anchor" href="#解析机制" aria-label="Permalink to &quot;解析机制&quot;">​</a></h2><p><code>resolveFor()</code> 是 Clearance 上下文授权的核心——完整 API 请参见<a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>。它按以下优先级顺序合并三个来源：</p><ol><li><strong>上下文角色授权</strong>——来自用户在此上下文中专门持有的角色所授予的权限（<code>clr_role_ctx</code>）。</li><li><strong>全局角色授权</strong>——来自用户全局分配的 Spatie 角色所授予的权限（因此 <code>super_admin</code> 及其他全局角色对任意上下文的 <code>canIn()</code> 检查都能满足）。</li><li><strong>按上下文的覆盖</strong>（<code>clr_ctx_overrides</code>）——<code>forced_on</code> 在上述基础上追加一个权限；<code>forced_off</code> 则移除它，即使该权限是由全局角色授予的也是如此。拒绝始终优先生效。</li></ol><div class="warning custom-block"><p class="custom-block-title">拒绝始终优先生效</p><p><code>forced_off</code> 会覆盖任何由全局角色或上下文角色授权所授予的权限。对于同一个用户/权限/上下文组合，除了移除该 <code>forced_off</code> 覆盖之外，没有任何方法能“压过”它。</p></div><h2 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h2><p>Clearance 拥有 6 个数据表，从不修改 Spatie 的核心数据表（<code>roles</code>、<code>permissions</code>、<code>model_has_roles</code>、<code>model_has_permissions</code>、<code>role_has_permissions</code>）。所有引用 <code>roles.id</code>/<code>permissions.id</code> 的外键都会在删除时级联，除非另有说明；Spatie 的数据表没有任何外键指向 <code>clr_*</code>。</p><table tabindex="0"><thead><tr><th>数据表</th><th>关键列</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>、<code>subject_key</code>（联合唯一）——<code>display_name</code>、<code>description</code>、<code>icon_svg</code>、<code>color</code>——角色或看守器的显示元数据</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code>（唯一，外键 -&gt; <code>roles</code>）——<code>is_locked</code>、<code>scope</code>（<code>global</code>|<code>contextual</code>）、<code>context_types</code>（json）——<code>parent_role_id</code>（可空外键 -&gt; <code>roles</code>，<code>ON DELETE SET NULL</code>）——上限角色</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code>（唯一）、<code>driver</code>、<code>provider</code>——通过面板管理的看守器</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code>（唯一）、<code>value</code>——运行时键/值存储（默认角色等）</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>、<code>role_id</code>（外键 -&gt; <code>roles</code>）、<code>context_type</code>、<code>context_id</code>——上下文角色分配，按 <code>(user, role, context_type, context_id)</code> 联合唯一</td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>、<code>role_id</code>（外键 -&gt; <code>roles</code>）、<code>permission_id</code>（外键 -&gt; <code>permissions</code>）、<code>context_type</code>、<code>context_id</code>、<code>type</code>（<code>forced_on</code>|<code>forced_off</code>）——按用户、按上下文的权限覆盖</td></tr></tbody></table><h2 id="从不触碰-spatie-的数据表" tabindex="-1">从不触碰 Spatie 的数据表 <a class="header-anchor" href="#从不触碰-spatie-的数据表" aria-label="Permalink to &quot;从不触碰 Spatie 的数据表&quot;">​</a></h2><p>Clearance 的设计是与 <code>spatie/laravel-permission</code> 并存，而不是取代它。Clearance 面板创建或编辑的每一条 <code>Role</code> 和 <code>Permission</code> 记录，都是货真价实的 Spatie 模型，存储在 Spatie 自己的数据表中。Clearance 从不运行任何会向 <code>roles</code>、<code>permissions</code>、<code>model_has_roles</code>、<code>model_has_permissions</code> 或 <code>role_has_permissions</code> 中任意一张表添加列、或写入外键的迁移。</p><p>Clearance 自身的所有数据——显示元数据、角色作用域与上限、上下文分配、按上下文的覆盖、看守器定义以及设置——完全存放在上述 6 张 <code>clr_*</code> 数据表中。这意味着：</p><ul><li>卸载 Clearance 永远不会有损坏你现有 Spatie 角色/权限数据的风险。</li><li>任何已经直接读取 Spatie 模型或数据表的代码都能不加修改地继续运行。</li><li>Clearance 的上下文和上限功能都是在查询时解析（通过 <code>resolveFor()</code> 和 <code>RoleService</code>）的纯附加层，并没有嵌入 Spatie 的表结构中。</li></ul><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/features/contextual-authorization.html">上下文授权</a>——<code>canIn()</code>、<code>hasRoleIn()</code>、Blade 指令、<code>ContextService</code></li><li><a href="/clearance-docs/zh/features/roles.html">角色</a>——作用域与上限角色、<code>RoleService::setParent()</code></li><li><a href="/clearance-docs/zh/guide/migration.html">迁移</a>——将 <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> 补充到已有的 Spatie 安装中</li><li><a href="/clearance-docs/zh/guide/security.html">安全性</a>——上限与覆盖模型如何防止权限提升</li></ul>',14)])])}const u=o(r,[["render",a]]);export{p as __pageData,u as default};
